  ('social-worker-moex-01271', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「符號互動論」對人類行為的敘述，何者較不恰當？', '["觀念與互動是了解人類行為的兩個重要變項", "人在不同情境下所持觀點亦會不同，這意味人類反應行為的動態性", "觀點是與生俱來的，參考團體無法左右", "語言、手勢、表情、文字等項，都屬符號的範疇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01272', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '夫妻關係有可能影響對子女的態度與行為，並進而影響子女的功能，然後子女的功能又倒過頭來 影響夫妻的婚姻關係。上述比較傾向下列何種家庭互動概念的內涵？', '["循環性", "結構性", "線性", "選擇性親近"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01273', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一個比較不符合兒童注意力缺陷過動症（ADHD）的特徵？', '["注意力不集中", "運動項目表現特優", "過動", "閱讀障礙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01274', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據Kirby&Fraser（1997）的研究，有關具韌性兒童的敘述，下列何者錯誤？', '["具韌性兒童是兒童在風險因素與保護因素相互作用下所產生的結果", "具韌性兒童指兒童固執不容易受他人影響", "具韌性兒童指兒童在不利條件下能夠不受影響", "不安全依附是韌性兒童的風險因素，而父母溫暖與支持是保護因素"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01275', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Howes（1997）曾經提出父母親評估幼兒園時的五點建議參考。下列那一項不在建議裡？', '["照顧者與孩子比率較低，孩子可以獲得較多的個別照顧", "幼兒園班級大小不應超過12至15個孩子", "照顧者應較成熟，經驗較豐富", "照顧者應該固定及較少輪調，使孩子與照顧者培養安全關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01276', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '研究顯示，嬰兒氣質可區分為三種類型：隨和（easybaby）、慢熟（slow-to-warmupbaby）及難 以相處（difficultbaby）。下列對於「慢熟型」嬰兒的敘述，何者正確？', '["能夠接受新的互動對象與環境", "對新的環境有些戒心和焦慮", "對新的環境情緒反應表現較激烈", "對新的環境完全無法適應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01277', 'social-worker', 'social-worker-moex-109-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關人類發展是受先天或後天影響的爭論不斷。有關先天與後天的敘述，下列選項何者較為恰', '["人類發展受遺傳基因的影響", "環境是人類發展的重要影響因素之一", "嬰兒不論出生 在那裡，因為具有先天的潛能都能正常發展", "人類發展是受遺傳與環境多重因素所影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "d61878d6b4b0", "answer_pdf_sha1": "9a0ef8d62143", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
